#include <stdio.h>
#define MOD 1000000007

long long countSubsequences(char *s, int n) {
    long long dp[n + 1][10] = {{0}};
    dp[0][0] = 1;
    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < 10; j++) {
            dp[i][j] = dp[i - 1][j];
        }
        int digit = s[i - 1] - '0';
        for (int j = 0; j < 10; j++) {
            int sum = (j * 10 + digit) % 9;
            dp[i][sum] = (dp[i][sum] + dp[i - 1][j]) % MOD;
        }
    }
    return (dp[n][0] + dp[n][9]) % MOD;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[10001];
        scanf("%s", s);
        int n = strlen(s);
        printf("%lld\n", countSubsequences(s, n));
    }
    return 0;
}

