                for (int j = 0; j < 10; j++) {
                    dp[i][j] = dp[i - 1][j];
                }
                int digit = s.charAt(i - 1) - '0';
                for (int j = 0; j < 10; j++) {
                    int sum = (j * 10 + digit) % 9;
                    dp[i][sum] = (dp[i][sum] + dp[i - 1][j]) % MOD;
                }
            }
            System.out.println((dp[n][0] + dp[n][9]) % MOD);
